#include <bits/stdc++.h>
using namespace std;
int m,r,n,a[45],dp[45][3005],t,ans;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>m>>r>>n;
	for (int i=1; i<=m; i++) {
		cin>>a[i];
		t+=a[i];
	}
	dp[0][0]=1;
	for (int i=1; i<=m; i++) {
		for (int j=r; j>=1; j--) {
			for (int k=a[i]; k<=t; k++) {
				dp[j][k]+=dp[j-1][k-a[i]];
			}
		}
	}
	for (int i=n+1; i<=t; i++) {
		ans+=dp[r][i];
	}
	cout<<ans;
	return 0;
}
